const article = items[0].json;

const prompt = `あなたはファクトチェッカーです。以下のAI生成記事の内容を確認してください。

【チェック対象記事】
${article.content}

【チェック項目】
1. 消費税率・控除額・法定数値に明らかな誤りがないか
2. 制度名・法律名・団体名が正確か（freee, マネーフォワード等のサービス名含む）
3. 論理的矛盾や事実と明らかに異なる記述がないか
4. 過度な誇大表現（「完全自動化」「100%正確」等）がないか

回答はJSONのみ（説明不要）:
{
  "passed": true または false,
  "issues": ["問題点1", "問題点2"],
  "confidence": 0.0〜1.0
}`;

return [{ json: { ...article, factCheckPrompt: prompt } }];

const responseText = items[0].json.candidates[0].content.parts[0].text;
const originalData = $('ファクトチェックプロンプト作成').first().json;

let result = { passed: true, issues: [], confidence: 0.8 };
try {
  const match = responseText.match(/\{[\s\S]*\}/m);
  if (match) result = JSON.parse(match[0]);
} catch (e) {
  console.error('ファクトチェックパースエラー:', responseText);
  // パースエラー時はpassedとして扱う（フォールバック）
}

console.log(`ファクトチェック: ${result.passed ? '✅ 合格' : '❌ 問題あり'} (信頼度: ${result.confidence})`);
if (result.issues.length > 0) console.log('問題点:', result.issues);

return [{
  json: {
    ...originalData,
    factCheckPassed: result.passed,
    factCheckIssues: result.issues,
    factCheckConfidence: result.confidence
  }
}];

const article = items[0].json;
console.log(`⚠️ ファクトチェック不合格のためスキップ: ${article.originalTitle}`);
console.log('問題点:', article.factCheckIssues);
return [];
